patch:
diff --git a/src/main/java/org/apache/commons/lang3/time/Instants.java b/src/main/java/org/apache/commons/lang3/time/Instants.java
--- a/src/main/java/org/apache/commons/lang3/time/Instants.java
+++ b/src/main/java/org/apache/commons/lang3/time/Instants.java
@@ -26,5 +30,5 @@
- */
-public class Instants {
+        return instant.getEpochSecond() < 0 ? negBound : posBound;
+    }

     /**
      * Converts an Instant to milliseconds bound to a {@code long} without throwing {@link ArithmeticException}.
@@ -34,7 +38,7 @@
      * </ul>
      *
      * @param instant The instant to convert, not null.
-     * @return long milliseconds.
+     * @return long The given Instant in milliseconds.
      * @see Instant#toEpochMilli()
      * @see Long#MIN_VALUE
      * @see Long#MAX_VALUE
@@ -43,6 +47,6 @@
         try {
             return instant.toEpochMilli();
         } catch (final ArithmeticException e) {
-            return instant.getEpochSecond() < 0 ? Long.MIN_VALUE : Long.MAX_VALUE;
+            return toBound(instant, Long.MIN_VALUE, Long.MAX_VALUE);
         }
     }
